void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var g = vector<vector<tuple<int, int, bool>>>(n + 1);
	fa(i, 1, m) {
		int u, v, w; cin >> u >> v >> w;
		g[u].pb({ v, w, 0 }), g[v].pb({ u, w, 0 });
	}
	var s = vector<int>(n + 1);
	var vis = vector<bool>(n + 1);
	var find = [&](var find, int x)->int {
		if (s[x] == x)return s[x];
		return s[x] = find(find, s[x]);
		};

	int ans = 0;
	fb(k, 30, 0) {
		fa(i, 1, n)s[i] = i, vis[i] = 0;

		var check = [&]()->bool {
			int cnt = n - 1; // 一共合并 n - 1 次
			var Q = queue<int>();
			Q.push(1);
			while (Q.size()) {
				int now = Q.front();
				Q.pop();
				if (vis[now])continue;
				vis[now] = 1;
				int e1 = find(find, now);
				for (const var& [to, w, f] : g[now]) {
					int e2 = find(find, to);
					if (f or vis[to] or e1 == e2 or (w & 1 << k))continue;
					s[e2] = e1;
					cnt--;
					if (cnt == 0)return 1;
					Q.push(to);
				}
			}
			return cnt == 0;
			};

		if (check()) {
			// ans 的 k 位答案可以是 0，也就是 k 位是 1 的边权一个不取
			// 那么把 k 位是 1 的边全删掉
			fa(i, 1, n)for (var& [to, w, f] : g[i]) {
				if (!f and (w & 1 << k))f = 1;
			}
		}
		else ans |= (1 << k);
	}
	cout << ans << endl;
	return;
}
